const Users = (props) => {
  return (
    <div>
      {props.users.map((user) => (
        <div key={user.id}>
          <span>
            <div>
              <img />
            </div>
          </span>
          <span>
            <button>Follow</button>
          </span>
        </div>
      ))}
    </div>
  );
};

export default Users;
